const typeData = $('🔍 تحديد نوع الرابط').first().json;
const jinaData = $('🌐 جلب المحتوى (Jina Premium)').first().json;
const aiData = $input.first().json;

const content = jinaData.body || jinaData.data || '';
const summary = aiData.response || '';
const wordCount = content.split(/\s+/).length;

const markdown = `---
title: "${typeData.title || typeData.url}"
url: ${typeData.url}
type: ${typeData.type}
date: ${typeData.timestamp}
words: ${wordCount}
source_file: ${typeData.fileName}
---

# ${typeData.title || 'محتوى من: ' + typeData.url}

**المصدر:** ${typeData.url}  
**النوع:** ${typeData.type}  
**التاريخ:** ${new Date(typeData.timestamp).toLocaleDateString('ar-SA')}  
**الملف الأصلي:** ${typeData.fileName}

---

## 📋 الملخص الذكي

${summary}

---

## 📄 المحتوى الكامل

${content}
`;

return [{ json: {
  ...typeData,
  markdown,
  wordCount
}}];

// تسجيل في السجل
const data = $('📝 بناء Markdown').first().json;
console.log(`✅ تمت معالجة: ${data.fileName} → ${data.outputFilename} (${data.wordCount} كلمة)`);
return [{ json: {
  success: true,
  sourceFile: data.fileName,
  outputFile: data.outputFilename,
  url: data.url,
  type: data.type,
  words: data.wordCount,
